const CORNER: [number, number][] = [];
for (let i = 0; i <= 10; i++) {
    const t = (Math.PI / 2) * (i / 10);
    CORNER.push([Math.cos(t) ** EPOW, Math.sin(t) ** EPOW]);
}
const QT: number[] = [];
for (let i = 1; i <= 12; i++) {
    QT.push(i / 13);
}

function buildPath(p: number[], bx: number): string {
    const cx = bx + p[0],
        cy = CY + p[1];
    const w = Math.max(8, p[2]),
        h = Math.max(10, p[3]);
    const x0 = cx - w / 2,
        x1 = cx + w / 2;
    const yT = cy - h / 2,
        yB = cy + h / 2;
    const half = Math.min(w / 2, h / 2);
    const cl = (r: number) => Math.max(3, Math.min(r, half));
    const rTL = cl(p[4]),
        rTR = cl(p[5]),
        rBL = cl(p[6]),
        rBR = cl(p[7]);
    const tT = p[8],
        tB = p[9],
        bT = p[10],
        bB = p[11];
    const pts: number[] = [];
    const push = (x: number, y: number) => pts.push(x, y);
    const bumpEdge = (x0e: number, x1e: number, yb: number, amt: number) => {
        for (const u of QT) {
            const s = Math.sin(Math.PI * u);
            push(x0e + (x1e - x0e) * u, yb + amt * s * s);
        }
    };
    push(x0 + rTL, yT);
    bumpEdge(x0 + rTL, x1 - rTR, yT, -bT);
    push(x1 - rTR, yT);
    for (let i = 9; i >= 0; i--) {
        push(x1 - rTR + rTR * CORNER[i][0], yT + rTR - rTR * CORNER[i][1]);
    }
    push(x1, yB - rBR);
    for (let i = 1; i <= 10; i++) {
        push(x1 - rBR + rBR * CORNER[i][0], yB - rBR + rBR * CORNER[i][1]);
    }
    bumpEdge(x1 - rBR, x0 + rBL, yB, bB);
    push(x0 + rBL, yB);
    for (let i = 9; i >= 0; i--) {
        push(x0 + rBL - rBL * CORNER[i][0], yB - rBL + rBL * CORNER[i][1]);
    }
    push(x0, yT + rTL);
    for (let i = 1; i <= 10; i++) {
        push(x0 + rTL - rTL * CORNER[i][0], yT + rTL - rTL * CORNER[i][1]);
    }
    const cres = p[13] || 0;
    if (cres > 0.001) {
        crescentBlend(pts, cx, cy, w, h, Math.min(1, cres));
    }
    const rot = (p[12] || 0) * 0.017_453_3;
    const cosR = Math.cos(rot),
        sinR = Math.sin(rot);
    let d = '';
    const hw = w / 2,
        hh = Math.max(1, yB - yT);
    for (let i = 0; i < pts.length; i += 2) {
        let x = pts[i];
        let y = pts[i + 1];
        let u = (y - yT) / hh;
        u = u < 0 ? 0 : u > 1 ? 1 : u;
        const fT = (1 - u) * (1 - u),
            fB = u * u;
        y += (tT * fT + tB * fB) * ((x - cx) / hw);
        if (rot) {
            const rx = x - cx,
                ry = y - cy;
            x = cx + rx * cosR - ry * sinR;
            y = cy + rx * sinR + ry * cosR;
        }
        d += `${i === 0 ? 'M' : 'L'}${x.toFixed(1)} ${y.toFixed(1)}`;
    }
    return `${d}Z`;
}

function crescentBlend(pts: number[], cx: number, cy: number, w: number, th: number, k: number) {
    const TH = 2.7925;
    const R = w / 2 / Math.sin(TH / 2);
    const rise = R * (1 - Math.cos(TH / 2));
    const cyA = cy + (R - rise / 2);
    const cl = (u: number): [number, number, number, number, number, number] => {
        const phi = Math.PI / 2 + TH / 2 - TH * u;
        const nx = Math.cos(phi),
            ny = -Math.sin(phi);
        return [cx + R * nx, cyA + R * ny, nx, ny, Math.sin(phi), Math.cos(phi)];
    };
    const thick = (u: number) => th * (0.3 + 0.7 * Math.sin(Math.PI * u) ** 0.8);
    const c2: number[] = [];
    for (let i = 0; i < 26; i++) {
        const u = i / 25,
            q = cl(u),
            r = thick(u) / 2;
        c2.push(q[0] + q[2] * r, q[1] + q[3] * r);
    }
    {
        const q = cl(1),
            r = thick(1) / 2;
        for (let j = 1; j <= 6; j++) {
            const psi = Math.PI / 2 - (Math.PI * j) / 7,
                s = Math.sin(psi),
                c = Math.cos(psi);
            c2.push(q[0] + r * (s * q[2] + c * q[4]), q[1] + r * (s * q[3] + c * q[5]));
        }
    }
    for (let i = 0; i < 30; i++) {
        const u = 1 - i / 29,
            q = cl(u),
            r = thick(u) / 2;
        c2.push(q[0] - q[2] * r, q[1] - q[3] * r);
    }
    {
        const q = cl(0),
            r = thick(0) / 2;
        for (let j = 1; j <= 7; j++) {
            const psi = -Math.PI / 2 + (Math.PI * j) / 8,
                s = Math.sin(psi),
                c = Math.cos(psi);
            c2.push(q[0] + r * (s * q[2] - c * q[4]), q[1] + r * (s * q[3] - c * q[5]));
        }
    }
    for (let i = 0; i < pts.length; i++) {
        pts[i] = pts[i] * (1 - k) + c2[i] * k;
    }
}

const easeInQuad = (p: number) => p * p;
const easeOutBack = (p: number) => {
    const c = 1.2;
    return 1 + (c + 1) * (p - 1) ** 3 + c * (p - 1) ** 2;
};
