/* ───────────────────────────────────────────────────────────
   Adding or updating a character avatar? Full recipe (art here + the
   agentCharacters contract in @tavern/api): docs/internals/agent-avatars.md

   THE FRAME CONTRACT — one standard, zero per-head tuning.
   Canvas: 480×480. Eyes ALWAYS render at EYE_FRAME below; every head's
   art is pre-fit to it. To author a new head:
     1. Import template-480.svg into Fable as a guide layer
        (dashed frame + the resting eyes at their exact standard spot).
     2. Draw the head around those eyes. Keep the frame rect in the export
        so the exported viewBox stays the full 480 square.
     3. Registry entry — two export styles:
        · Fable:  FIT = "translate(0 0) scale(1)", T = the export's matrix,
                  FULL/OUTER = the path (outer subpath first), via fableArt.
        · Figma:  already 480×480 with no transforms and baked-in backings —
                  paste the <path> elements verbatim as the art group.
   No slot, no fit-tuning — the head just drops in.
   ─────────────────────────────────────────────────────────── */
const EYE_FRAME = { dx: 0, dy: 24, s: 0.5 };

// Renders a Fable-exported head: paper backing + ink line art. Ink uses
// currentColor so dark mode recolors the marks via the svg `color` style
// instead of shipping separate dark art.
const fableArt = (
    key: string,
    FIT: string,
    T: string,
    OUTER: string,
    FULL: string
): ReactElement => (
    <g key={key} transform={FIT}>
        <g transform={T}>
            <path d={OUTER} fill={PAPER} />
            <path d={FULL} fill="currentColor" fillRule="nonzero" />
        </g>
    </g>
);

// One art set per head. Ink marks and dark eyes use currentColor, so the whole
// face recolors through the svg `color` style (INK in light mode, the agent's
// dark-mode ink in dark mode). White stays white in both themes.
const HEADS = {
    none: (_dark: boolean) => ({
        back: [],
        front: [],
        eyeColor: DARKEYE,
        slot: { dx: 0, dy: 0, s: 1 },
    }),

    // ── Penguin: template-native art (white face panel + ink body)
    penguin: (_dark: boolean) => ({
        back: [PEN_ART],
        front: [],
        eyeColor: 'currentColor',
    }),

    // ── Robot: template-native art (white screen + ink body)
    robot: (_dark: boolean) => ({
        back: [ROBOT_ART],
        front: [],
        eyeColor: 'currentColor',
    }),

    // ── Cat: real Fable art (solid silhouette + white inner ears), white eyes on top
    cat: (_dark: boolean) => ({
        back: [fableArt('art', CAT_FIT, CAT_T, CAT_OUTER, CAT_FULL)],
        front: [],
        eyeColor: PAPER, // white eyes on the ink face
    }),

    // ── Dog: real Fable art (silhouette + floppy ears + white face window + nose), dark eyes seated above the nose
    dog: (_dark: boolean) => ({
        back: [fableArt('art', DOG_FIT, DOG_T, DOG_OUTER, DOG_FULL)],
        front: [],
        eyeColor: 'currentColor',
    }),
    // ── Ghost: real Fable art (white body + wavy outline + face window), dark eyes
    ghost: (_dark: boolean) => ({
        back: [fableArt('art', GHOST_FIT, GHOST_T, GHOST_OUTER, GHOST_FULL)],
        front: [],
        eyeColor: 'currentColor',
    }),
    // ── Cloud: real Fable art (puffy body + scalloped outline + face window), dark eyes
    cloud: (_dark: boolean) => ({
        back: [fableArt('art', CLOUD_FIT, CLOUD_T, CLOUD_OUTER, CLOUD_FULL)],
        front: [],
        eyeColor: 'currentColor',
    }),
    // ── Knight: real Fable art (helmet silhouette + white visor window), dark eyes in the visor
    knight: (_dark: boolean) => ({
        back: [fableArt('art', KNIGHT_FIT, KNIGHT_T, KNIGHT_OUTER, KNIGHT_FULL)],
        front: [],
        eyeColor: 'currentColor',
    }),
} satisfies Record<string, (dark: boolean) => HeadSpec>;
export type HeadName = keyof typeof HEADS;
export const HEAD_KINDS = Object.keys(HEADS) as HeadName[];

/* ───────────────────────────────────────────────────────────
   AgentFace
   ─────────────────────────────────────────────────────────── */

export interface AgentFaceProps {
    animate?: boolean;
    blinking?: boolean;
    color?: string;
    dark?: boolean;
    emotion?: Emotion;
    guide?: boolean;
    head?: HeadName;
    /** Ink color for the head's marks and dark eyes. Defaults to INK; pass the
     *  agent's dark-mode ink (see resolveAgentInk) on dark backgrounds. */
    ink?: string;
    intensity?: number;
    size?: number;
    slot?: Slot;
    speed?: number;
    style?: CSSProperties;
}

export function AgentFace({
    head = 'none',
    dark = false, // dark-background variant — pair with your app's web dark mode
    emotion = 'default',
    color = DARKEYE,
    ink = INK,
    size = 320,
    intensity = 1,
    speed = 1,
    blinking = true,
    animate = true, // false = render the emotion pose statically, no rAF loop.
    // Use for message-row avatars; animate only the "live" one.
    guide = false, // overlay the standard frame + resting eye placement (authoring aid)
    slot, // optional { dx, dy, s } override
    style,
}: AgentFaceProps) {
    const faceRef = useRef<SVGGElement | null>(null);
    const lRef = useRef<SVGPathElement | null>(null),
        rRef = useRef<SVGPathElement | null>(null),
        dropRef = useRef<SVGPathElement | null>(null);
    const pr = useRef({ emotion, intensity, speed, blinking });
    pr.current = { emotion, intensity, speed, blinking };

    useEffect(() => {
        if (!animate) {
            return; // static pose handled by the effect below
        }
        const reduce =
            typeof window !== 'undefined' &&
            window.matchMedia &&
            window.matchMedia('(prefers-reduced-motion: reduce)').matches;
        const cur = { L: D.slice(), R: D.slice() };
        const vel = { L: new Array(14).fill(0), R: new Array(14).fill(0) };
        const tgt: number[] = new Array(14);
        let lastEmotion: Emotion | null = null;
        let boing = 0,
            boingVel = 0; // now drives the whole face group
        let blinkV = 0,
            blinkStart = -1,
            doubleQueued = false;
        let nextBlink = performance.now() + 900 + Math.random() * 1200;
        let raf = 0,
            last = performance.now();

        const loop = (now: number) => {
            raf = requestAnimationFrame(loop);
            const P = pr.current;
            const dt = Math.min(0.033, (now - last) / 1000) || 0.016;
            last = now;
            const t = now / 1000;
            const emo: EmoDef = EMO[P.emotion] || EMO.default;
            const inten = Math.max(0, Math.min(1.25, P.intensity));
            const sp = Math.max(0.2, P.speed);
            const k = 165 * sp * sp;
            const c = 2 * 0.72 * Math.sqrt(k);
            const changed = P.emotion !== lastEmotion;
            if (changed) {
                lastEmotion = P.emotion;
                boingVel -= 1.5 * sp;
            }

            const bk = 130 * sp * sp,
                bc = 2 * 0.3 * Math.sqrt(bk);
            boingVel += (-bk * boing - bc * boingVel) * dt;
            boing += boingVel * dt;

            for (const side of ['L', 'R'] as const) {
                const cu = cur[side],
                    ve = vel[side],
                    em = emo[side];
                for (let i = 0; i < 14; i++) {
                    tgt[i] = D[i] + (em[i] - D[i]) * inten;
                    if (changed) {
                        ve[i] -= (tgt[i] - cu[i]) * 3.2;
                    }
                    ve[i] += (k * (tgt[i] - cu[i]) - c * ve[i]) * dt;
                    cu[i] += ve[i] * dt;
                }
            }

            const bp = BLINK[emo.blink];
            if (P.blinking && bp) {
                if (blinkStart < 0 && now >= nextBlink) {
                    blinkStart = now;
                }
                if (blinkStart >= 0) {
                    const e = now - blinkStart;
                    const { close, hold, open } = bp;
                    if (e < close) {
                        blinkV = easeInQuad(e / close);
                    } else if (e < close + hold) {
                        blinkV = 1;
                    } else if (e < close + hold + open) {
                        blinkV = 1 - easeOutBack((e - close - hold) / open);
                    } else {
                        blinkV = 0;
                        blinkStart = -1;
                        if (!doubleQueued && Math.random() < 0.22) {
                            nextBlink = now + 240;
                            doubleQueued = true;
                        } else {
                            doubleQueued = false;
                            nextBlink = now + (bp.min + Math.random() * bp.rand) * 1000;
                        }
                    }
                }
            } else if (blinkV !== 0) {
                blinkV = Math.max(0, blinkV - dt * 7);
                blinkStart = -1;
            }

            const breath = emo.breath || 1;
            const resolve = (side: 'L' | 'R') => {
                const p = cur[side].slice();
                // NOTE: per-eye boing removed — the face group owns squash/stretch
                p[1] += Math.sin(t * Math.PI * 2 * 0.22) * 2.2 * breath;
                p[3] += Math.sin(t * Math.PI * 2 * 0.22 + 0.6) * 1.8 * breath;
                if (emo.bounce) {
                    const lbp = (t % 2.3) / 2.3;
                    const env = lbp < 0.62 ? Math.sqrt(Math.sin((Math.PI * lbp) / 0.62)) : 0;
                    const ha = Math.max(0, Math.sin(t * Math.PI * 2 * 3.3)) ** 2.2;
                    const kk = env * ha;
                    p[1] -= kk * 15;
                    p[3] -= kk * 9;
                    p[2] += kk * 7;
                    p[11] -= kk * 12;
                    p[12] += Math.sin(t * Math.PI * 2 * 1.65) * env * 2.2;
                }
                if (emo.sway) {
                    p[0] += Math.sin(t * Math.PI * 2 * 0.5) * (side === 'R' ? 5 : 1.6);
                    if (side === 'R') {
                        p[12] += Math.sin(t * Math.PI * 2 * 0.5) * 2;
                    }
                }
                if (emo.ponder) {
                    const ST = [
                        [42, -18],
                        [-36, -26],
                        [18, 12],
                        [-44, -4],
                        [38, -30],
                        [-10, 16],
                    ];
                    const iv = 1.6;
                    const n = Math.floor(t / iv);
                    const a = ST[n % 6],
                        b = ST[(n + 1) % 6];
                    let e = Math.min(1, (t / iv - n) * 5);
                    e = e * e * (3 - 2 * e);
                    const gx = a[0] + (b[0] - a[0]) * e;
                    const gy = a[1] + (b[1] - a[1]) * e;
                    p[0] += gx;
                    p[1] += gy;
                    p[12] += gx * 0.07;
                    const s = Math.max(0.8, 1 - Math.hypot(gx, gy) * 0.0035);
                    p[2] *= s;
                    p[3] *= s;
                    p[4] *= s;
                    p[5] *= s;
                    p[6] *= s;
                    p[7] *= s;
                    p[3] += Math.sin(t * Math.PI * 2 * 1.1) * 5;
                }
                if (emo.tremor) {
                    p[0] += Math.sin(t * Math.PI * 2 * 9) * (side === 'R' ? 1.1 : -1.1);
                }
                if (blinkV !== 0) {
                    const v = blinkV,
                        vc = Math.max(0, v);
                    p[1] += vc * p[3] * 0.2;
                    p[3] += (Math.min(p[3], 34) - p[3]) * v;
                    p[8] *= 1 - vc;
                    p[9] *= 1 - vc;
                    p[10] *= 1 - vc;
                    p[11] *= 1 - vc;
                }
                return p;
            };

            if (lRef.current) {
                lRef.current.setAttribute('d', buildPath(resolve('L'), LX));
            }
            if (rRef.current) {
                rRef.current.setAttribute('d', buildPath(resolve('R'), RX));
            }

            // sweat drop (eye-local)
            const dropV = emo.drop ? 1 : 0;
            if (dropRef.current) {
                if (dropV && !reduce) {
                    const cyc = (t % 1.9) / 1.9;
                    let s = 1,
                        y = 92,
                        o = 0;
                    if (cyc < 0.18) {
                        const q = cyc / 0.18;
                        s = 0.35 + 0.65 * q;
                        o = q;
                    } else if (cyc < 0.62) {
                        const q = (cyc - 0.18) / 0.44;
                        y = 92 + 118 * q * q;
                        o = 1;
                    } else if (cyc < 0.78) {
                        const q = (cyc - 0.62) / 0.16;
                        y = 210 + 14 * q;
                        o = 1 - q;
                    } else {
                        o = 0;
                    }
                    dropRef.current.setAttribute(
                        'transform',
                        `translate(444 ${y.toFixed(1)}) scale(${(s * 2.8).toFixed(3)})`
                    );
                    dropRef.current.setAttribute('opacity', (o * 0.95).toFixed(3));
                } else {
                    dropRef.current.setAttribute('opacity', '0');
                }
            }

            // FACE GROUP — breath bob + boing squash for the whole body, as one.
            if (faceRef.current) {
                const breathY = reduce ? 0 : Math.sin(t * Math.PI * 2 * 0.22) * 3 * breath;
                const bz = reduce ? 0 : Math.max(-0.3, Math.min(0.3, boing));
                const s = 1 + bz;
                const ty = breathY - bz * 12;
                const px = 240,
                    py = 320; // pivot near the base → grounded, jelly-like squash
                faceRef.current.setAttribute(
                    'transform',
                    `translate(0 ${ty.toFixed(2)}) translate(${px} ${py}) scale(${s.toFixed(4)}) translate(${-px} ${-py})`
                );
            }
        };
        raf = requestAnimationFrame(loop);
        return () => cancelAnimationFrame(raf);
    }, [animate]);

    // Static pose: paints the exact emotion target once, no loop. Message-row
    // avatars cost nothing at rest; flipping animate back on springs to life.
    useEffect(() => {
        if (animate) {
            return;
        }
        const emo: EmoDef = EMO[emotion] || EMO.default;
        const inten = Math.max(0, Math.min(1.25, intensity));
        const pose = (side: 'L' | 'R') => {
            const p: number[] = new Array(14);
            for (let i = 0; i < 14; i++) {
                p[i] = D[i] + (emo[side][i] - D[i]) * inten;
            }
            return p;
        };
        if (lRef.current) {
            lRef.current.setAttribute('d', buildPath(pose('L'), LX));
        }
        if (rRef.current) {
            rRef.current.setAttribute('d', buildPath(pose('R'), RX));
        }
        if (faceRef.current) {
            faceRef.current.setAttribute('transform', '');
        }
        if (dropRef.current) {
            dropRef.current.setAttribute('opacity', '0');
        }
    }, [animate, emotion, intensity]);

    const H: HeadSpec = (HEADS[head] || HEADS.none)(dark);
    const sl = slot || H.slot || EYE_FRAME;
    const eyeColor = head === 'none' ? (dark ? LIGHTEYE : color) : H.eyeColor;
    const slotTf = `translate(${sl.dx} ${sl.dy}) translate(${CY} ${CY}) scale(${sl.s}) translate(${-CY} ${-CY})`;

    return (
        <svg
            aria-label={`${head} agent, ${emotion}`}
            height={size}
            style={{ color: ink, ...style }}
            viewBox={`0 0 ${VB} ${VB}`}
            width={size}
        >
            <g ref={faceRef}>
                {H.back}
                <g transform={slotTf}>
                    <path fill={eyeColor} ref={lRef} />
                    <path fill={eyeColor} ref={rRef} />
                    <path d={DROP} fill="#5fb8f6" opacity="0" ref={dropRef} />
                </g>
                {H.front}
            </g>
            {guide && (
                <g pointerEvents="none">
                    <rect
                        fill="none"
                        height={VB - 4}
                        opacity="0.8"
                        stroke="#e0457b"
                        strokeDasharray="12 9"
                        strokeWidth="3"
                        width={VB - 4}
                        x="2"
                        y="2"
                    />
                    <line
                        opacity="0.35"
                        stroke="#e0457b"
                        strokeWidth="1.5"
                        x1={VB / 2}
                        x2={VB / 2}
                        y1="0"
                        y2={VB}
                    />
                    <g opacity="0.85" transform={slotTf}>
                        <path
                            d={buildPath(D, LX)}
                            fill="none"
                            stroke="#e0457b"
                            strokeDasharray={`${18 / sl.s} ${13 / sl.s}`}
                            strokeWidth={7 / sl.s}
                        />
                        <path
                            d={buildPath(D, RX)}
                            fill="none"
                            stroke="#e0457b"
                            strokeDasharray={`${18 / sl.s} ${13 / sl.s}`}
                            strokeWidth={7 / sl.s}
                        />
                    </g>
                </g>
            )}
        </svg>
    );
}

export default AgentFace;
